// 2.8.0 | 2022-05-19 |raj |  STRY0118079 - Tasker Application Admin (TAA) inherit Global Hierarchy Admin (GHA) permissions
// 2.8    | 2022-09-08 - raj -  STRY0129039 - OU Hierarchy Group Not Configured for Role Warning
// 2.8    | 2022-09-08 - raj -  STRY0129041 - Block Search for User if Groups are Selected but aren't Configured
// Script Continued Below


(function executeRule(current, previous /*null when async*/) {

	// STRY0129041
	var isNewRecord = current.isNewRecord();
	var user = "";
	if(!isNewRecord){
		user = current.office_member;
	}
	var permissions = new UserInfoScripts().getUserGlobalRolesAndMessages(user);
	g_scratchpad.userRolesAndPermissions = permissions;


	for(var i=0; i<permissions.length; i++){
		var permission = permissions[i];
		if(!isNewRecord && 
			permission.fieldName && permission.fieldName != ''){
			current.setValue(permission.fieldName, permission.hasRole);
		}
	}
})(current, previous);
